const b = $input.first().json.body || $input.first().json;
if (!b.projectName) throw new Error('projectName obrigatorio');
if (!b.profiles || !Array.isArray(b.profiles) || b.profiles.length === 0) throw new Error('profiles obrigatorio');
if (!b.geminiKey) throw new Error('geminiKey obrigatorio');
return [{ json: b }];

const data = $input.first().json;
const profiles = data.profiles;

function calcMetrics(p) {
  const rows = p.rows || [];
  const posts = rows.length;
  const likesArr = rows.filter(r => r.Curtidas !== 'Oculto').map(r => parseInt(r.Curtidas) || 0);
  const avgLikes = likesArr.length > 0 ? Math.round(likesArr.reduce((s,v) => s+v, 0) / likesArr.length) : 0;
  const avgComments = posts > 0 ? Math.round(rows.reduce((s,r) => s + (parseInt(r.Comentarios) || 0), 0) / posts) : 0;
  const followers = p.followerCount || 0;
  const engRate = followers > 0 ? (((avgLikes + avgComments) / followers) * 100).toFixed(2) : '0.00';
  const themes = {};
  const tones = {};
  const formats = {};
  rows.forEach(r => {
    const t = r.Tema || 'Outros'; themes[t] = (themes[t] || 0) + 1;
    const v = r.Tom_de_Voz || 'Outros'; tones[v] = (tones[v] || 0) + 1;
    const f = r.Formato || 'Foto'; formats[f] = (formats[f] || 0) + 1;
  });
  const topThemes = Object.entries(themes).sort((a,b) => b[1]-a[1]).slice(0,5).map(([k,v]) => k + ' (' + v + 'x)').join(', ');
  const topTones = Object.entries(tones).sort((a,b) => b[1]-a[1]).slice(0,3).map(([k,v]) => k + ' (' + v + 'x)').join(', ');
  const topFormats = Object.entries(formats).sort((a,b) => b[1]-a[1]).map(([k,v]) => k + ': ' + v).join(', ');
  return { posts, avgLikes, avgComments, followers, engRate, topThemes, topTones, topFormats, themes, tones, formats };
}

const summaries = profiles.map(p => {
  const m = calcMetrics(p);
  return '## ' + (p.isMain ? '[PERFIL PRINCIPAL]' : '[BENCHMARK]') + ' @' + p.handle + '\n' +
    '- Seguidores: ' + (m.followers > 0 ? m.followers.toLocaleString('pt-BR') : 'N/D') + '\n' +
    '- Posts analisados: ' + m.posts + '\n' +
    '- Média de curtidas por post: ' + m.avgLikes + '\n' +
    '- Média de comentários por post: ' + m.avgComments + '\n' +
    '- Taxa de engajamento: ' + m.engRate + '%\n' +
    '- Formatos: ' + (m.topFormats || 'N/D') + '\n' +
    '- Temas principais: ' + (m.topThemes || 'N/D') + '\n' +
    '- Tons predominantes: ' + (m.topTones || 'N/D');
});

const prompt = 'Você é especialista em marketing digital e estratégia de redes sociais.\n\n' +
  'Analise os dados de ' + profiles.length + ' perfil(is) do Instagram para o projeto "' + data.projectName + '" e gere uma análise comparativa profissional e acionável.\n\n' +
  summaries.join('\n\n') + '\n\n' +
  'Com base nesses dados, retorne SOMENTE um JSON válido com esta estrutura:\n' +
  '{\n' +
  '  "resumo_executivo": "2-3 parágrafos resumindo os principais achados da análise comparativa",\n' +
  '  "analise_principal": "análise do perfil principal em relação aos benchmarks (2-3 parágrafos, comparando métricas, estratégia e posicionamento)",\n' +
  '  "analise_conteudo": "análise dos formatos, temas e estratégia de conteúdo com base nos dados (2 parágrafos)",\n' +
  '  "analise_engajamento": "análise das taxas de engajamento, o que indicam sobre a audiência e a qualidade do conteúdo (2 parágrafos)",\n' +
  '  "analise_tom": "análise dos tons de voz utilizados e como eles refletem o posicionamento de cada perfil (1-2 parágrafos)",\n' +
  '  "recomendacoes": ["rec 1", "rec 2", "rec 3", "rec 4", "rec 5"],\n' +
  '  "pontos_atencao": ["ponto 1", "ponto 2", "ponto 3"],\n' +
  '  "proximos_passos": ["passo 1", "passo 2", "passo 3"]\n' +
  '}';

return [{ json: { prompt, profiles, projectName: data.projectName, geminiKey: data.geminiKey, registrySheetId: data.registrySheetId || '' } }];

const geminiResp = $input.first().json;
const ctx = $('Preparar Prompt Análise').first().json;
const profiles = ctx.profiles;
const projectName = ctx.projectName;

let analysis = {};
try {
  const text = geminiResp.choices?.[0]?.message?.content || '{}';
  analysis = JSON.parse(text);
} catch(e) {
  analysis = {
    resumo_executivo: 'Análise concluída com sucesso.',
    analise_principal: 'Perfil principal avaliado em relação aos benchmarks.',
    analise_conteudo: 'Dados de conteúdo processados.',
    analise_engajamento: 'Métricas de engajamento calculadas.',
    analise_tom: 'Análise de tom de voz disponível na planilha.',
    recomendacoes: ['Revisar estratégia de conteúdo com base nos dados coletados.'],
    pontos_atencao: ['Verificar dados nas planilhas individuais.'],
    proximos_passos: ['Implementar as recomendações no próximo ciclo de conteúdo.']
  };
}

function calcMetrics(p) {
  const rows = p.rows || [];
  const posts = rows.length;
  const likesArr = rows.filter(r => r.Curtidas !== 'Oculto').map(r => parseInt(r.Curtidas) || 0);
  const avgLikes = likesArr.length > 0 ? Math.round(likesArr.reduce((s,v) => s+v, 0) / likesArr.length) : 0;
  const avgComments = posts > 0 ? Math.round(rows.reduce((s,r) => s + (parseInt(r.Comentarios) || 0), 0) / posts) : 0;
  const followers = p.followerCount || 0;
  const engRate = followers > 0 ? (((avgLikes + avgComments) / followers) * 100).toFixed(2) : '0.00';
  const formats = {};
  rows.forEach(r => { const f = r.Formato || 'Foto'; formats[f] = (formats[f] || 0) + 1; });
  const themes = {};
  rows.forEach(r => { const t = r.Tema || 'Outros'; themes[t] = (themes[t] || 0) + 1; });
  const topRows = rows
    .filter(r => r.Curtidas !== 'Oculto')
    .map(r => ({ ...r, _score: (parseInt(r.Curtidas) || 0) + (parseInt(r.Comentarios) || 0) * 3 }))
    .sort((a, b) => b._score - a._score)
    .slice(0, 3);
  return { posts, avgLikes, avgComments, followers, engRate, formats, themes, topRows };
}

const today = new Date().toLocaleDateString('pt-BR');
const mainProfile = profiles.find(p => p.isMain) || profiles[0];
const benchmarks = profiles.filter(p => !p.isMain);

function esc(s) { return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
function fmtNum(n) { return Number(n).toLocaleString('pt-BR'); }

let html = '<!DOCTYPE html><html lang="pt-BR"><head><meta charset="UTF-8"><title>Análise Competitiva: ' + esc(projectName) + '</title>';
html += '<style>';
html += 'body{font-family:Arial,sans-serif;font-size:11pt;color:#222;max-width:800px;margin:0 auto;padding:20px;}';
html += 'h1{font-size:20pt;color:#1a1a2e;border-bottom:3px solid #3a86ff;padding-bottom:10px;}';
html += 'h2{font-size:14pt;color:#3a86ff;margin-top:30px;border-left:4px solid #3a86ff;padding-left:10px;}';
html += 'h3{font-size:12pt;color:#333;}';
html += 'table{width:100%;border-collapse:collapse;margin:15px 0;font-size:10pt;}';
html += 'th{background:#3a86ff;color:#fff;padding:8px 10px;text-align:left;}';
html += 'td{padding:7px 10px;border-bottom:1px solid #eee;}';
html += 'tr:nth-child(even) td{background:#f7f9ff;}';
html += '.highlight{background:#fff3cd;font-weight:bold;}';
html += '.main-label{background:#3a86ff;color:#fff;padding:2px 8px;border-radius:3px;font-size:9pt;}';
html += '.bench-label{background:#6c757d;color:#fff;padding:2px 8px;border-radius:3px;font-size:9pt;}';
html += '.rec-list{padding-left:20px;}';
html += '.rec-list li{margin:8px 0;line-height:1.6;}';
html += 'p{line-height:1.8;margin:10px 0;}';
html += '.meta{color:#888;font-size:9pt;margin-bottom:20px;}';
html += '.tag{display:inline-block;background:#e8f4fd;border:1px solid #bee3f8;padding:2px 8px;border-radius:12px;font-size:9pt;margin:2px;}';
html += '</style></head><body>';

html += '<h1>📊 Análise Competitiva de Instagram</h1>';
html += '<p class="meta">Projeto: <strong>' + esc(projectName) + '</strong> &nbsp;|&nbsp; Data: ' + today + '</p>';
html += '<p class="meta">Perfis analisados: ';
profiles.forEach(p => {
  html += '<span class="tag">' + (p.isMain ? '⭐ ' : '') + '@' + esc(p.handle) + '</span> ';
});
html += '</p>';

html += '<h2>1. Resumo Executivo</h2>';
html += '<p>' + esc(analysis.resumo_executivo || '').replace(/\n\n/g, '</p><p>') + '</p>';

html += '<h2>2. Métricas Comparativas</h2>';
html += '<table><thead><tr>';
html += '<th>Perfil</th><th>Seguidores</th><th>Posts</th><th>Méd. Curtidas</th><th>Méd. Comentários</th><th>Tx. Engajamento</th>';
html += '</tr></thead><tbody>';
profiles.forEach(p => {
  const m = calcMetrics(p);
  const isMain = p.isMain;
  const cls = isMain ? ' class="highlight"' : '';
  html += '<tr' + cls + '><td>' + (isMain ? '<span class="main-label">Principal</span> ' : '<span class="bench-label">Benchmark</span> ') + '@' + esc(p.handle) + '</td>';
  html += '<td>' + (m.followers > 0 ? fmtNum(m.followers) : 'N/D') + '</td>';
  html += '<td>' + m.posts + '</td>';
  html += '<td>' + fmtNum(m.avgLikes) + '</td>';
  html += '<td>' + fmtNum(m.avgComments) + '</td>';
  html += '<td>' + m.engRate + '%</td></tr>';
});
html += '</tbody></table>';

html += '<h2>3. Análise do Perfil Principal</h2>';
html += '<p>' + esc(analysis.analise_principal || '').replace(/\n\n/g, '</p><p>') + '</p>';

html += '<h2>4. Formatos de Conteúdo</h2>';
html += '<table><thead><tr><th>Perfil</th><th>Reels (Vídeo)</th><th>Carrossel</th><th>Foto</th></tr></thead><tbody>';
profiles.forEach(p => {
  const m = calcMetrics(p);
  const total = p.rows ? p.rows.length : 0;
  const reels = m.formats['Reels'] || 0;
  const carrossel = m.formats['Carrossel'] || 0;
  const foto = m.formats['Foto'] || 0;
  const pct = (n) => total > 0 ? ' (' + Math.round(n/total*100) + '%)' : '';
  html += '<tr><td>' + (p.isMain ? '⭐ ' : '') + '@' + esc(p.handle) + '</td>';
  html += '<td>' + reels + pct(reels) + '</td>';
  html += '<td>' + carrossel + pct(carrossel) + '</td>';
  html += '<td>' + foto + pct(foto) + '</td></tr>';
});
html += '</tbody></table>';
html += '<p>' + esc(analysis.analise_conteudo || '').replace(/\n\n/g, '</p><p>') + '</p>';

html += '<h2>5. Temas Abordados</h2>';
profiles.forEach(p => {
  const m = calcMetrics(p);
  const topThemes = Object.entries(m.themes).sort((a,b) => b[1]-a[1]).slice(0, 6);
  html += '<h3>' + (p.isMain ? '⭐ ' : '') + '@' + esc(p.handle) + '</h3>';
  if (topThemes.length > 0) {
    html += '<table><thead><tr><th>Tema</th><th>Posts</th><th>%</th></tr></thead><tbody>';
    const total = p.rows ? p.rows.length : 1;
    topThemes.forEach(([k,v]) => {
      html += '<tr><td>' + esc(k) + '</td><td>' + v + '</td><td>' + Math.round(v/total*100) + '%</td></tr>';
    });
    html += '</tbody></table>';
  } else {
    html += '<p>Sem dados de tema.</p>';
  }
});

html += '<h2>6. Tom de Voz</h2>';
html += '<p>' + esc(analysis.analise_tom || '').replace(/\n\n/g, '</p><p>') + '</p>';
html += '<table><thead><tr><th>Perfil</th><th>Tom Predominante</th></tr></thead><tbody>';
profiles.forEach(p => {
  const rowTones = (p.rows || []).reduce((acc, r) => {
    const t = r.Tom_de_Voz || 'Outros';
    acc[t] = (acc[t] || 0) + 1;
    return acc;
  }, {});
  const mainTone = Object.entries(rowTones).sort((a,b) => b[1]-a[1])[0];
  html += '<tr><td>' + (p.isMain ? '⭐ ' : '') + '@' + esc(p.handle) + '</td>';
  html += '<td>' + esc(mainTone ? mainTone[0] : 'N/D') + '</td></tr>';
});
html += '</tbody></table>';

html += '<h2>7. Análise de Engajamento</h2>';
html += '<p>' + esc(analysis.analise_engajamento || '').replace(/\n\n/g, '</p><p>') + '</p>';
profiles.forEach(p => {
  const m = calcMetrics(p);
  if (m.topRows.length === 0) return;
  html += '<h3>🏆 Top Posts — @' + esc(p.handle) + '</h3>';
  html += '<table><thead><tr><th>#</th><th>Formato</th><th>Data</th><th>Curtidas</th><th>Comentários</th><th>Tema</th><th>Link</th></tr></thead><tbody>';
  m.topRows.forEach((r, i) => {
    html += '<tr><td>' + (i+1) + '</td><td>' + esc(r.Formato) + '</td><td>' + esc(r.Data) + '</td>';
    html += '<td>' + esc(r.Curtidas) + '</td><td>' + esc(r.Comentarios) + '</td>';
    html += '<td>' + esc(r.Tema) + '</td>';
    html += '<td><a href="' + esc(r.Link) + '">Ver post</a></td></tr>';
  });
  html += '</tbody></table>';
});

html += '<h2>8. Recomendações Estratégicas</h2>';
if (analysis.recomendacoes && analysis.recomendacoes.length > 0) {
  html += '<ul class="rec-list">';
  analysis.recomendacoes.forEach(r => { html += '<li>✅ ' + esc(r) + '</li>'; });
  html += '</ul>';
}
if (analysis.pontos_atencao && analysis.pontos_atencao.length > 0) {
  html += '<h3>⚠️ Pontos de Atenção</h3><ul class="rec-list">';
  analysis.pontos_atencao.forEach(r => { html += '<li>' + esc(r) + '</li>'; });
  html += '</ul>';
}
if (analysis.proximos_passos && analysis.proximos_passos.length > 0) {
  html += '<h3>🚀 Próximos Passos</h3><ul class="rec-list">';
  analysis.proximos_passos.forEach(r => { html += '<li>' + esc(r) + '</li>'; });
  html += '</ul>';
}

html += '<hr><p class="meta">Relatório gerado automaticamente em ' + today + ' | Sistema de Análise Competitiva de Instagram</p>';
html += '</body></html>';

const boundary = '====UploadBoundary====';
const docTitle = 'Análise Competitiva — ' + projectName + ' — ' + today;
const meta = JSON.stringify({ name: docTitle, mimeType: 'application/vnd.google-apps.document' });
const multipartBody = '--' + boundary + '\r\nContent-Type: application/json; charset=UTF-8\r\n\r\n' + meta + '\r\n--' + boundary + '\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n' + html + '\r\n--' + boundary + '--';

return [{ json: { multipartBody, boundary, docTitle, projectName: ctx.projectName, profiles: ctx.profiles, registrySheetId: ctx.registrySheetId, geminiKey: ctx.geminiKey } }];

const driveResp = $input.first().json;
const ctx = $('Gerar HTML e Preparar Upload').first().json;

const docId = driveResp.id;
const docUrl = driveResp.webViewLink || ('https://docs.google.com/document/d/' + docId + '/edit?usp=sharing');
const docTitle = ctx.docTitle;
const projectName = ctx.projectName;
const registrySheetId = ctx.registrySheetId || '';
const profiles = ctx.profiles;
const today = new Date().toLocaleDateString('pt-BR');
const mainProfile = (profiles.find(p => p.isMain) || profiles[0])?.handle || '';
const benchmarkHandles = profiles.filter(p => !p.isMain).map(p => '@' + p.handle).join(', ');

return [{ json: { docId, docUrl, docTitle, projectName, registrySheetId, mainProfile, benchmarkHandles, today, totalProfiles: profiles.length } }];

const prev = $('Processar Resposta Doc').first().json;
return [{ json: {
  status: 'success',
  docUrl: prev.docUrl,
  docId: prev.docId,
  docTitle: prev.docTitle
} }];

// Only fire callback if jobId + callbackUrl were provided (async proxy mode)
const vars = $('Validar Input').first().json;
const callbackUrl = vars.callbackUrl || '';
const jobId = vars.jobId || '';
if (!callbackUrl || !jobId) return [];
const result = $input.first().json;
return [{ json: { callbackUrl, jobId, result } }];
